import sys
from functools import lru_cache
input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))

    @lru_cache(maxsize=None)
    def dp(l, r, prev):
        # returns True if current player wins
        moves = []
        if l <= r:
            if a[l] > prev:
                moves.append(not dp(l+1, r, a[l]))
            if a[r] > prev and r != l:
                moves.append(not dp(l, r-1, a[r]))
        if not moves:
            return False
        return any(moves)

    if dp(0, n-1, -1):
        print("Alice")
    else:
        print("Bob")

solve()

